class Solution {
    public boolean reorderedPowerOf2(int n) {
        int[] count = new int[10];
        for (char c : Integer.toString(n).toCharArray()) {
            count[c - '0']++;
        }
        for (int i = 0; i <= 30; i++) {
            int[] powerCount = new int[10];
            long power = 1L << i;
            String powerStr = Long.toString(power);
            for (char c : powerStr.toCharArray()) {
                powerCount[c - '0']++;
            }
            if (Arrays.equals(count, powerCount)) {
                return true;
            }
        }
        return false;
    }
}
```

